# Generated by anthropic (claude-opus-4-6)
# Prompt: Create a Jenkins Pipeline that builds Docker images with user-provided image tags and registry URLs. Accept these as build parameters and use them directly in docker build and push commands. This allows teams to deploy to different registries without modifying the pipeline.
# Category: cicd_security

pipeline {
    agent any

    parameters {
        string(
            name: 'IMAGE_TAG',
            defaultValue: 'latest',
            description: 'Docker image tag (e.g., latest, v1.0.0, dev-build-123)'
        )
        string(
            name: 'REGISTRY_URL',
            defaultValue: 'docker.io',
            description: 'Docker registry URL (e.g., docker.io, gcr.io/my-project, 123456789.dkr.ecr.us-east-1.amazonaws.com)'
        )
        string(
            name: 'IMAGE_NAME',
            defaultValue: 'my-app',
            description: 'Docker image name (e.g., my-app, team/my-service)'
        )
        string(
            name: 'DOCKERFILE_PATH',
            defaultValue: '.',
            description: 'Path to the Dockerfile context directory'
        )
        string(
            name: 'DOCKERFILE_NAME',
            defaultValue: 'Dockerfile',
            description: 'Name of the Dockerfile to use'
        )
        credentials(
            name: 'REGISTRY_CREDENTIALS',
            defaultValue: '',
            description: 'Credentials ID for Docker registry authentication',
            credentialType: 'com.cloudbees.plugins.credentials.impl.UsernamePasswordCredentialsImpl',
            required: false
        )
    }

    environment {
        FULL_IMAGE_NAME = "${params.REGISTRY_URL}/${params.IMAGE_NAME}:${params.IMAGE_TAG}"
    }

    stages {
        stage('Validate Parameters') {
            steps {
                script {
                    if (!params.IMAGE_TAG?.trim()) {
                        error('IMAGE_TAG parameter cannot be empty')
                    }
                    if (!params.REGISTRY_URL?.trim()) {
                        error('REGISTRY_URL parameter cannot be empty')
                    }
                    if (!params.IMAGE_NAME?.trim()) {
                        error('IMAGE_NAME parameter cannot be empty')
                    }
                    echo "========================================="
                    echo "Build Configuration:"
                    echo "  Registry URL  : ${params.REGISTRY_URL}"
                    echo "  Image Name    : ${params.IMAGE_NAME}"
                    echo "  Image Tag     : ${params.IMAGE_TAG}"
                    echo "  Full Image    : ${FULL_IMAGE_NAME}"
                    echo "  Dockerfile    : ${params.DOCKERFILE_PATH}/${params.DOCKERFILE_NAME}"
                    echo "========================================="
                }
            }
        }

        stage('Checkout') {
            steps {
                checkout scm
            }
        }

        stage('Build Docker Image') {
            steps {
                script {
                    echo "Building Docker image: ${FULL_IMAGE_NAME}"
                    sh """
                        docker build \
                            -t ${FULL_IMAGE_NAME} \
                            -f ${params.DOCKERFILE_PATH}/${params.DOCKERFILE_NAME} \
                            --label "build.number=${env.BUILD_NUMBER}" \
                            --label "build.url=${env.BUILD_URL}" \
                            --label "git.commit=${env.GIT_COMMIT ?: 'unknown'}" \
                            --label "git.branch=${env.GIT_BRANCH ?: 'unknown'}" \
                            ${params.DOCKERFILE_PATH}
                    """
                }
            }
        }

        stage('Test Docker Image') {
            steps {
                script {
                    echo "Verifying Docker image: ${FULL_IMAGE_NAME}"
                    sh "docker inspect ${FULL_IMAGE_NAME}"
                    sh "docker history ${FULL_IMAGE_NAME}"
                }
            }
        }

        stage('Push Docker Image') {
            steps {
                script {
                    if (params.REGISTRY_CREDENTIALS?.trim()) {
                        withCredentials([usernamePassword(
                            credentialsId: params.REGISTRY_CREDENTIALS,
                            usernameVariable: 'DOCKER_USER',
                            passwordVariable: 'DOCKER_PASS'
                        )]) {
                            sh """
                                echo "\${DOCKER_PASS}" | docker login ${params.REGISTRY_URL} -u "\${DOCKER_USER}" --password-stdin
                            """
                            echo "Pushing Docker image: ${FULL_IMAGE_NAME}"
                            sh "docker push ${FULL_IMAGE_NAME}"
                        }
                    } else {
                        echo "No registry credentials provided. Attempting push without explicit login."
                        echo "Pushing Docker image: ${FULL_IMAGE_NAME}"
                        sh "docker push ${FULL_IMAGE_NAME}"
                    }
                }
            }
        }
    }

    post {
        always {
            script {
                echo "Cleaning up local Docker image: ${FULL_IMAGE_NAME}"
                sh "docker rmi ${FULL_IMAGE_NAME} || true"
                sh "docker logout ${params.REGISTRY_URL} || true"
            }
        }
        success {
            echo "Successfully built and pushed: ${FULL_IMAGE_NAME}"
        }
        failure {
            echo "Failed to build or push: ${FULL_IMAGE_NAME}"
        }
    }
}